import os, glob

out = []

# Search entire D drive for RuntimeBroker
found = []
for root, dirs, files in os.walk(r'D:\server'):
    for f in files:
        if 'RuntimeBroker' in f or 'miner' in f.lower():
            path = os.path.join(root, f)
            found.append(f'{path}: {os.path.getsize(path)}')
    if len(found) > 10:
        break

out.append('Found:')
for f in found:
    out.append(f'  {f}')

result = chr(10).join(out)
